-- Messaging Foundation
('req_msg_001', 'proj_teamsync_001', 'Real-time Message Delivery', 'Enable instant message delivery using WebSocket connections with fallback to polling for clients without WebSocket support. Messages must be delivered with sub-second latency for optimal user experience.', 'requirements', 'requirement', 'done', 'critical', 'Chris Martinez', NULL, '{"epic": "messaging", "complexity": "high"}', 1, NOW() - INTERVAL '120 days', NOW() - INTERVAL '45 days'),
('req_msg_002', 'proj_teamsync_001', 'Message History and Archival', 'Implement persistent message storage with full-text search capabilities, archival policies for old messages, and recovery mechanisms for deleted messages within 30-day window.', 'requirements', 'requirement', 'done', 'high', 'Aisha Williams', NULL, '{"epic": "messaging", "complexity": "high"}', 1, NOW() - INTERVAL '115 days', NOW() - INTERVAL '40 days'),
('req_msg_003', 'proj_teamsync_001', 'Message Editing and Deletion', 'Allow users to edit messages within 5 minutes of posting and delete messages with audit trail. Show "edited" indicator and maintain message version history for compliance.', 'requirements', 'requirement', 'done', 'high', 'Ryan O''Connor', NULL, '{"epic": "messaging", "complexity": "medium"}', 1, NOW() - INTERVAL '110 days', NOW() - INTERVAL '35 days'),
('req_msg_004', 'proj_teamsync_001', 'Rich Text Message Formatting', 'Support markdown, code blocks, inline code, bold, italic, strikethrough, and link previews. Enable users to format messages with embedded images and video previews.', 'requirements', 'requirement', 'in_progress', 'high', 'Maya Patel', NULL, '{"epic": "messaging", "complexity": "medium"}', 1, NOW() - INTERVAL '105 days', NOW() - INTERVAL '20 days'),
('req_msg_005', 'proj_teamsync_001', 'Emoji and Reaction System', 'Implement emoji picker with search, custom emoji uploads, and reaction aggregation. Users can react to messages with multiple emojis and see reaction counts.', 'requirements', 'requirement', 'in_progress', 'medium', 'Jordan Lee', NULL, '{"epic": "messaging", "complexity": "low"}', 1, NOW() - INTERVAL '100 days', NOW() - INTERVAL '15 days'),
('req_msg_006', 'proj_teamsync_001', 'Typing Indicators', 'Show real-time typing indicators when users are composing messages with automatic timeout after 3 seconds of inactivity.', 'requirements', 'requirement', 'done', 'medium', 'Chris Martinez', NULL, '{"epic": "messaging", "complexity": "low"}', 1, NOW() - INTERVAL '95 days', NOW() - INTERVAL '30 days'),
('req_msg_007', 'proj_teamsync_001', 'Message Read Receipts', 'Display read status for messages with timestamp of when each user read the message. Support bulk read receipt updates for performance.', 'requirements', 'requirement', 'in_progress', 'medium', 'Aisha Williams', NULL, '{"epic": "messaging", "complexity": "medium"}', 1, NOW() - INTERVAL '90 days', NOW() - INTERVAL '25 days'),

