VALUES
-- Messaging User Stories
('story_msg_001', 'proj_teamsync_001', 'User Story: Team member sends message in channel', 'As a team member, I want to send a message in a channel so that I can communicate with my colleagues. Acceptance: Message appears instantly, shows delivery status, can be edited within 5 minutes.', 'user_stories', 'user_story', 'done', 'critical', 'Chris Martinez', 'feat_msg_001', '{"epic": "messaging", "story_points": 5}', 1, NOW() - INTERVAL '110 days', NOW() - INTERVAL '35 days'),
('story_msg_002', 'proj_teamsync_001', 'User Story: User receives real-time message notification', 'As a user, I want to receive notifications instantly when someone messages me so that I do not miss important communications. Acceptance: Push notification within 1 second, desktop alert, sound option.', 'user_stories', 'user_story', 'done', 'high', 'Aisha Williams', 'feat_msg_002', '{"epic": "messaging", "story_points": 3}', 1, NOW() - INTERVAL '108 days', NOW() - INTERVAL '33 days'),
('story_msg_003', 'proj_teamsync_001', 'User Story: User formats message with markdown', 'As a user, I want to format messages using markdown syntax so that my messages are more readable and expressive. Acceptance: Support bold, italic, code blocks, lists, links with live preview.', 'user_stories', 'user_story', 'in_progress', 'high', 'Ryan O''Connor', 'feat_msg_007', '{"epic": "messaging", "story_points": 3}', 1, NOW() - INTERVAL '106 days', NOW() - INTERVAL '31 days'),
('story_msg_004', 'proj_teamsync_001', 'User Story: User reacts to message with emoji', 'As a user, I want to react to messages with emoji so that I can express quick feedback without writing a message. Acceptance: Emoji picker accessible, reactions visible on message, aggregated counts.', 'user_stories', 'user_story', 'in_progress', 'medium', 'Maya Patel', 'feat_msg_009', '{"epic": "messaging", "story_points": 2}', 1, NOW() - INTERVAL '104 days', NOW() - INTERVAL '29 days'),
('story_msg_005', 'proj_teamsync_001', 'User Story: User views message read receipts', 'As a user, I want to know who has read my messages so that I can track engagement. Acceptance: Show read status per message, display user avatars with timestamps.', 'user_stories', 'user_story', 'in_progress', 'medium', 'Jordan Lee', 'feat_msg_012', '{"epic": "messaging", "story_points": 3}', 1, NOW() - INTERVAL '102 days', NOW() - INTERVAL '27 days'),
('story_msg_006', 'proj_teamsync_001', 'User Story: User searches message history', 'As a user, I want to search through past messages so that I can find relevant information from previous conversations. Acceptance: Full-text search, filter by date/user/channel, saved searches.', 'user_stories', 'user_story', 'in_progress', 'high', 'Chris Martinez', 'feat_msg_004', '{"epic": "messaging", "story_points": 5}', 1, NOW() - INTERVAL '100 days', NOW() - INTERVAL '25 days'),
('story_msg_007', 'proj_teamsync_001', 'User Story: User edits sent message', 'As a user, I want to edit a message after sending it so that I can correct typos or clarify my message. Acceptance: Edit within 5 minutes, show "edited" label, preserve message history.', 'user_stories', 'user_story', 'done', 'medium', 'Aisha Williams', 'feat_msg_005', '{"epic": "messaging", "story_points": 2}', 1, NOW() - INTERVAL '98 days', NOW() - INTERVAL '23 days'),
('story_msg_008', 'proj_teamsync_001', 'User Story: User deletes message with recovery', 'As a user, I want to delete a message so that I can remove messages I sent by mistake. Acceptance: Soft delete with 30-day recovery, admin restoration, archive removal.', 'user_stories', 'user_story', 'done', 'high', 'Ryan O''Connor', 'feat_msg_006', '{"epic": "messaging", "story_points": 3}', 1, NOW() - INTERVAL '96 days', NOW() - INTERVAL '21 days'),

-- Channel User Stories
('story_chan_001', 'proj_teamsync_001', 'User Story: Admin creates public channel', 'As a workspace admin, I want to create a public channel so that team members can discover and join relevant discussions. Acceptance: Set channel name, description, topic, visibility settings.', 'user_stories', 'user_story', 'done', 'critical', 'Maya Patel', 'feat_chan_001', '{"epic": "channels", "story_points": 3}', 1, NOW() - INTERVAL '110 days', NOW() - INTERVAL '35 days'),
('story_chan_002', 'proj_teamsync_001', 'User Story: Member joins public channel', 'As a team member, I want to join a public channel so that I can participate in team discussions. Acceptance: Discover channels, join with one click, receive welcome message.', 'user_stories', 'user_story', 'done', 'high', 'Jordan Lee', 'feat_chan_001', '{"epic": "channels", "story_points": 2}', 1, NOW() - INTERVAL '108 days', NOW() - INTERVAL '33 days'),
('story_chan_003', 'proj_teamsync_001', 'User Story: Owner manages channel members', 'As a channel owner, I want to manage channel members so that I can control who has access to sensitive discussions. Acceptance: Add/remove members, assign roles, manage permissions.', 'user_stories', 'user_story', 'done', 'high', 'Chris Martinez', 'feat_chan_002', '{"epic": "channels", "story_points": 4}', 1, NOW() - INTERVAL '106 days', NOW() - INTERVAL '31 days'),
('story_chan_004', 'proj_teamsync_001', 'User Story: User configures channel notifications', 'As a user, I want to configure how I receive notifications from a channel so that I am not overwhelmed by notifications. Acceptance: All/mentions/none options, quiet hours, notification grouping.', 'user_stories', 'user_story', 'done', 'medium', 'Aisha Williams', 'feat_chan_004', '{"epic": "channels", "story_points": 2}', 1, NOW() - INTERVAL '104 days', NOW() - INTERVAL '29 days'),
('story_chan_005', 'proj_teamsync_001', 'User Story: User searches for channels', 'As a user, I want to search for channels so that I can find relevant discussions and join them. Acceptance: Search by name, description, member count, view suggestions.', 'user_stories', 'user_story', 'in_progress', 'medium', 'Ryan O''Connor', 'feat_chan_006', '{"epic": "channels", "story_points": 3}', 1, NOW() - INTERVAL '102 days', NOW() - INTERVAL '27 days'),
('story_chan_006', 'proj_teamsync_001', 'User Story: Channel owner receives invite link', 'As a channel owner, I want to generate invite links so that I can invite external users to the channel. Acceptance: Time-limited links, one-time use option, custom expiration policies.', 'user_stories', 'user_story', 'done', 'high', 'Maya Patel', 'feat_chan_003', '{"epic": "channels", "story_points": 3}', 1, NOW() - INTERVAL '100 days', NOW() - INTERVAL '25 days'),

-- Direct Message User Stories
('story_dm_001', 'proj_teamsync_001', 'User Story: User sends direct message', 'As a user, I want to send direct messages to colleagues so that I can have private conversations. Acceptance: Start DM with any user, message history, typing indicators.', 'user_stories', 'user_story', 'done', 'critical', 'Jordan Lee', 'feat_dm_001', '{"epic": "direct_messages", "story_points": 3}', 1, NOW() - INTERVAL '110 days', NOW() - INTERVAL '35 days'),
('story_dm_002', 'proj_teamsync_001', 'User Story: User sees online status', 'As a user, I want to see if my colleague is online so that I know when they might respond to my message. Acceptance: Show online/offline/away status, last seen time, presence indicators.', 'user_stories', 'user_story', 'done', 'high', 'Chris Martinez', 'feat_dm_003', '{"epic": "direct_messages", "story_points": 2}', 1, NOW() - INTERVAL '108 days', NOW() - INTERVAL '33 days'),
('story_dm_003', 'proj_teamsync_001', 'User Story: User creates group DM', 'As a user, I want to create group direct messages so that I can have private conversations with multiple people. Acceptance: Add up to 20 participants, set group name, manage members.', 'user_stories', 'user_story', 'in_progress', 'medium', 'Aisha Williams', 'feat_dm_004', '{"epic": "direct_messages", "story_points": 4}', 1, NOW() - INTERVAL '106 days', NOW() - INTERVAL '31 days'),

