('story_mention_001', 'proj_teamsync_001', 'User Story: User mentions colleague in message', 'As a user, I want to mention a colleague by name so that they receive a notification about my message. Acceptance: @mention autocomplete, notifications sent, highlighted in messages.', 'user_stories', 'user_story', 'done', 'critical', 'Jordan Lee', 'feat_mention_001', '{"epic": "mentions", "story_points": 2}', 1, NOW() - INTERVAL '110 days', NOW() - INTERVAL '35 days'),
('story_mention_002', 'proj_teamsync_001', 'User Story: User receives mention notification', 'As a user, I want to be notified when someone mentions me so that I can respond promptly. Acceptance: Instant push notification, separate notification category, history tracking.', 'user_stories', 'user_story', 'done', 'critical', 'Chris Martinez', 'feat_mention_003', '{"epic": "mentions", "story_points": 2}', 1, NOW() - INTERVAL '108 days', NOW() - INTERVAL '33 days'),
